#include<bits/stdc++.h>
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}const int MAXN=5e3+5;
int n,f[MAXN];
//f={inf} f[0]=0
//f[i]=min(f[i-5]{i>=5},f[i-3]{f>=3})+1
int main(void){
    //freopen("SECER.in","r",stdin);
    //freopen("SECER.out","w",stdout);
    memset(f,0x3f3f,sizeof f);f[0]=0;
    n=read();
    for(int i=1;i<=n;++i){
    	if(i>=3)f[i]=min(f[i],f[i-3]+1);
		if(i>=5)f[i]=min(f[i],f[i-5]+1);
	}if(f[n]==1061109567)printf("-1");
    else write(f[n]);
    return false;
}
